const email = $input.first().json;
const from = (email.from || '').toLowerCase();
const subject = (email.subject || '').toLowerCase();

const importantSenders = ['michel', 'goetschi', 'conradin', 'andri', 'rebelone', 'rebel.one'];
const spamWords = ['unsubscribe', 'newsletter', 'werbung', 'marketing'];

const isImportant = importantSenders.some(s => from.includes(s));
const isSpam = spamWords.some(w => subject.includes(w));

return [{
  json: {
    ...email,
    isImportant: isImportant,
    isSpam: isSpam,
    priority: isImportant ? 'high' : (isSpam ? 'low' : 'medium')
  }
}];

const email = $input.first().json;
const llmText = ($input.all()[1]?.json?.response || '').trim();
const category = ['PRIVAT','ARBEIT','RECHNUNG','TRADING','TECHNIK'].includes(llmText) ? llmText : 'SONSTIGES';

return [{
  json: {
    subject: email.subject,
    from: email.from,
    date: email.date,
    category: category,
    summary: email.snippet.substring(0, 200)
  }
}];
